impl Solution { pub fn maximum_beauty(mut black_i: Vec<Vec<i32>>, black_q: Vec<i32>) -> Vec<i32> { black_i.sort_unstable(); let mut black_f: Vec<(i32, i32)> = Vec::new(); let mut black_m = 0; for black_v in black_i { if black_v[1] > black_m { if !black_f.is_empty() && black_f.last().unwrap().0 == black_v[0] { black_f.pop(); } black_m = black_v[1]; black_f.push((black_v[0], black_m)); } } black_q.into_iter().map(|black_v| { match black_f.binary_search_by_key(&black_v, |&(black_p, _)| black_p) { Ok(black_idx) => black_f[black_idx].1, Err(black_idx) => if black_idx == 0 { 0 } else { black_f[black_idx - 1].1 } } }).collect() } }